// Internal spotlight painter for [BTPaginationStepController].
//
// Paints a semi-transparent dark layer over the full canvas with a
// rounded-rect cutout at [spotlight] (border-radius 5 px) — the
// equivalent of the web `box-shadow: 0 0 0 9999px rgba(0,0,0,0.55)`
// trick used by [BTPaginationStepTour] in Vue / React.

import 'package:flutter/rendering.dart';

class BTSpotlightPainter extends CustomPainter {
  const BTSpotlightPainter({required this.spotlight, required this.color});

  final Rect spotlight;
  final Color color;

  @override
  void paint(Canvas canvas, Size size) {
    final path = Path()
      ..fillType = PathFillType.evenOdd
      ..addRect(Rect.fromLTWH(0, 0, size.width, size.height))
      ..addRRect(RRect.fromRectAndRadius(spotlight, const Radius.circular(5)));
    canvas.drawPath(path, Paint()..color = color);
  }

  @override
  bool shouldRepaint(covariant BTSpotlightPainter oldDelegate) =>
      oldDelegate.spotlight != spotlight || oldDelegate.color != color;
}

// Barrel for the BTPaginationStepTour organism.

export '../pagination_step/pagination_step_controller.dart';
export '../pagination_step/pagination_step_widget.dart';

// ignore_for_file: lines_longer_than_80_chars

import '../tooltip-step/tooltip_step.types.dart';
import '../tooltip-step/tooltip_step.widget.dart';
import 'package:btech_ui/src/components/organisms/pagination_step/internal/spotlight_painter.dart';
import 'package:btech_ui/src/components/organisms/pagination_step/pagination_step_widget.dart';
import 'package:flutter/material.dart';
import 'package:flutter/scheduler.dart';

/// Manages a multi-step PaginationStep tour using Flutter's [Overlay].
///
/// Provide a list of [BTPaginationStep]s. Call [show] to start the tour;
/// [dismiss] to end it early; always call [dispose] when the host widget
/// is removed.
///
/// ```dart
/// final _tour = BTPaginationStepController(
///   steps: [
///     BTPaginationStepStep(
///       targetKey: _myKey,
///       description: 'Tap here to continue.',
///       stepLabel: 'Step 1 of 3',
///       position: BTTooltipPosition.bottom,
///     ),
///   ],
///   dismissable: true,
///   onFinish: () => print('done'),
/// );
///
/// // In dispose():
/// _tour.dispose();
///
/// // Show starting at step 0:
/// _tour.show(context);
///
/// // Or jump to a specific step (e.g. when user clicks button i):
/// _tour.show(context, startAt: i);
/// ```
class BTPaginationStepController {
  BTPaginationStepController({
    required this.steps,
    this.dismissable = true,
    this.stepVariant = BTTooltipStepVariant.button,
    this.prevLabel = 'Prev',
    this.nextLabel = 'Next',
    this.onFinish,
  }) {
    _animCtrl = AnimationController(
      vsync: _SimpleTickerProvider(),
      duration: const Duration(milliseconds: 200),
    );
  }

  final List<BTPaginationStep> steps;
  final bool dismissable;
  final BTTooltipStepVariant stepVariant;
  final String prevLabel;
  final String nextLabel;
  final VoidCallback? onFinish;

  late final AnimationController _animCtrl;
  OverlayEntry? _backdropEntry;
  OverlayEntry? _stepEntry;
  int _activeIdx = -1;
  bool _navigating = false;

  // Two-pass measurement for left/right centering.
  Size? _stepMeasuredSize;

  static const double _balloonW = 320;
  static const double _balloonH = 160;
  // _spotlightPad (4) + 6px visual gap from spotlight border = 10
  static const double _gap = 10;
  static const double _arrowSz = 8;
  static const double _spotlightPad = 4;

  // ── Public API ────────────────────────────────────────────────────────────

  /// Show the PaginationStep tour, starting at [startAt] (default 0).
  void show(BuildContext context, {int startAt = 0}) {
    assert(
      startAt >= 0 && startAt < steps.length,
      'startAt must be a valid step index.',
    );
    _removeEntries();
    _animCtrl.reset();
    _insertEntries(context, startAt);
    _animCtrl.forward();
  }

  /// Dismiss the active PaginationStep (if any) with fade-out.
  void dismiss() => _close();

  /// Currently visible step index, or -1 if no tour is active.
  int get activeIndex => _activeIdx;

  void dispose() {
    _removeEntries();
    _animCtrl.dispose();
  }

  // ── Internal ──────────────────────────────────────────────────────────────

  void _removeEntries() {
    _stepEntry?.remove();
    _backdropEntry?.remove();
    _stepEntry = null;
    _backdropEntry = null;
  }

  void _insertEntries(BuildContext context, int idx) {
    if (idx < 0 || idx >= steps.length) return;
    _activeIdx = idx;
    _stepMeasuredSize = null;
    final step = steps[idx];
    final box = step.targetKey.currentContext?.findRenderObject() as RenderBox?;
    if (box == null) return;

    final triggerOffset = box.localToGlobal(Offset.zero);
    final triggerSize = box.size;
    final screenSize = MediaQuery.of(context).size;

    final tcx = triggerOffset.dx + triggerSize.width / 2;
    final tcy = triggerOffset.dy + triggerSize.height / 2;

    final position = step.position ??
        _autoPosition(triggerOffset, triggerSize, screenSize);

    // ── Horizontal position (left edge) — independent of balloon height ──
    double left;
    switch (position) {
      case BTTooltipPosition.top:
      case BTTooltipPosition.bottom:
        left = tcx - _balloonW / 2;
      case BTTooltipPosition.left:
        left = triggerOffset.dx - _balloonW - _arrowSz - _gap;
      case BTTooltipPosition.right:
        left = triggerOffset.dx + triggerSize.width + _gap;
    }
    left = left.clamp(8.0, screenSize.width - _balloonW - 8.0);

    // arrowOffset: horizontal (tcx - left) for top/bottom; unused for left/right
    final arrowOffset =
        (position == BTTooltipPosition.left || position == BTTooltipPosition.right)
            ? null
            : tcx - left;

    final spotlight = Rect.fromLTWH(
      triggerOffset.dx - _spotlightPad,
      triggerOffset.dy - _spotlightPad,
      triggerSize.width + _spotlightPad * 2,
      triggerSize.height + _spotlightPad * 2,
    );

    final curvedAnim = CurvedAnimation(
      parent: _animCtrl,
      curve: Curves.easeInOut,
    );

    _backdropEntry = OverlayEntry(
      builder: (_) => Positioned.fill(
        child: FadeTransition(
          opacity: _animCtrl,
          child: GestureDetector(
            behavior: HitTestBehavior.opaque,
            onTap: dismissable ? _close : null,
            child: CustomPaint(
              painter: BTSpotlightPainter(
                spotlight: spotlight,
                color: Colors.black.withValues(alpha: 0.55),
              ),
              child: const SizedBox.expand(),
            ),
          ),
        ),
      ),
    );

    final prevLabelFinal = step.prevLabel ?? prevLabel;
    final nextLabelFinal = step.nextLabel ?? nextLabel;
    final variantFinal = step.stepVariant;

    // Fresh GlobalKey per step — identifies the rendered BTTooltipStep.
    final capturedKey = GlobalKey();

    _stepEntry = OverlayEntry(
      builder: (_) {
        // For left/right: use measured height (pass 2) or estimate (pass 1).
        final h = _stepMeasuredSize?.height ?? _balloonH;

        switch (position) {
          // ── top: anchor widget BOTTOM to trigger top − gap ──────────────
          // Height-independent — balloon grows upward regardless of content.
          case BTTooltipPosition.top:
            return Positioned(
              bottom: screenSize.height - triggerOffset.dy + _gap,
              left: left,
              child: _buildStepWidget(curvedAnim, step, position, arrowOffset,
                  capturedKey, idx, context, prevLabelFinal, nextLabelFinal, variantFinal,),
            );

          // ── bottom: anchor widget TOP to trigger bottom + gap ────────────
          case BTTooltipPosition.bottom:
            return Positioned(
              top: triggerOffset.dy + triggerSize.height + _gap,
              left: left,
              child: _buildStepWidget(curvedAnim, step, position, arrowOffset,
                  capturedKey, idx, context, prevLabelFinal, nextLabelFinal, variantFinal,),
            );

          // ── left/right: center on trigger mid-Y using measured height ────
          case BTTooltipPosition.left:
          case BTTooltipPosition.right:
            final centeredTop =
                (tcy - h / 2).clamp(8.0, screenSize.height - h - 8.0);
            return Positioned(
              top: centeredTop,
              left: left,
              child: _buildStepWidget(curvedAnim, step, position, null,
                  capturedKey, idx, context, prevLabelFinal, nextLabelFinal, variantFinal,),
            );
        }
      },
    );

    Overlay.of(context, rootOverlay: true)
      ..insert(_backdropEntry!)
      ..insert(_stepEntry!);

    // Pass 2: measure actual balloon height → re-center left/right tooltip.
    WidgetsBinding.instance.addPostFrameCallback((_) {
      final stepBox =
          capturedKey.currentContext?.findRenderObject() as RenderBox?;
      if (stepBox != null && _stepMeasuredSize == null) {
        _stepMeasuredSize = stepBox.size;
        if (position == BTTooltipPosition.left ||
            position == BTTooltipPosition.right) {
          _stepEntry?.markNeedsBuild();
        }
      }
    });
  }

  Widget _buildStepWidget(
    Animation<double> curvedAnim,
    BTPaginationStep step,
    BTTooltipPosition position,
    double? arrowOffset,
    GlobalKey stepKey,
    int idx,
    BuildContext context,
    String prevLabelFinal,
    String nextLabelFinal,
    BTTooltipStepVariant variantFinal,
  ) {
    return FadeTransition(
      opacity: curvedAnim,
      child: ScaleTransition(
        scale: Tween<double>(begin: 0.92, end: 1).animate(curvedAnim),
        child: Material(
          color: Colors.transparent,
          child: BTTooltipStep(
            key: stepKey,
            label: step.label,
            description: step.description,
            stepLabel: step.stepLabel,
            stepVariant: variantFinal,
            hasClose: true,
            prevLabel: prevLabelFinal,
            nextLabel: nextLabelFinal,
            position: position,
            arrowOffset: arrowOffset,
            onPrev: idx > 0 ? () => _navigate(context, idx - 1) : _close,
            onNext: idx < steps.length - 1
                ? () => _navigate(context, idx + 1)
                : _finish,
            onClose: _close,
          ),
        ),
      ),
    );
  }

  BTTooltipPosition _autoPosition(Offset offset, Size size, Size screen) {
    final cy = offset.dy + size.height / 2;
    return cy > screen.height * 0.6
        ? BTTooltipPosition.top
        : BTTooltipPosition.bottom;
  }

  void _navigate(BuildContext context, int idx) {
    if (_navigating) return;
    _navigating = true;
    _animCtrl.reverse().then((_) {
      _removeEntries();
      _animCtrl.reset();
      _insertEntries(context, idx);
      _animCtrl.forward().then((_) {
        _navigating = false;
      });
    });
  }

  void _close() {
    if (_navigating) return;
    _animCtrl.reverse().then((_) {
      _removeEntries();
      _activeIdx = -1;
    });
  }

  void _finish() {
    _close();
    onFinish?.call();
  }
}

// ── Internal TickerProvider that doesn't require a State ─────────────────────

class _SimpleTickerProvider implements TickerProvider {
  @override
  Ticker createTicker(TickerCallback onTick) => Ticker(onTick);
}

// BTPaginationStepStep — single-step descriptor for [BTPaginationStepController].
//
// One [BTPaginationStepStep] describes one balloon in a PaginationStep tour:
// which widget to highlight (via [GlobalKey]), what copy to display,
// and where the balloon should appear relative to the target.

import '../tooltip-step/tooltip_step.types.dart';
import 'package:flutter/widgets.dart';

/// Descriptor for a single step in a [BTPaginationStepController] tour.
class BTPaginationStep {
  const BTPaginationStep({
    required this.targetKey,
    required this.description,
    this.label,
    this.stepLabel,
    this.stepVariant = BTTooltipStepVariant.button,
    this.position,
    this.prevLabel,
    this.nextLabel,
  });

  /// Key attached to the widget that should be highlighted.
  final GlobalKey targetKey;

  /// Description text inside the balloon (required).
  final String description;

  /// Optional bold title shown at the top of the balloon.
  final String? label;

  /// Step indicator, e.g. "Step 1 of 3".
  final String? stepLabel;

  /// Navigation footer style. Defaults to [BTTooltipStepVariant.button].
  final BTTooltipStepVariant stepVariant;

  /// Balloon position. When `null` it is auto-detected from the target's
  /// position in the viewport (bottom half → top, otherwise → bottom).
  final BTTooltipPosition? position;

  /// Per-step override for the prev button label.
  final String? prevLabel;

  /// Per-step override for the next button label.
  final String? nextLabel;
}
